#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <cuda_runtime.h>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
    for (int j = 0; j < N; ++j) {
        for (int i = 0; i < N; ++i) {
            if (i == 0 || i == N-1) {
                f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
            }
            else if (j == 0 || j == N-1) {
                f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
            }
            else {
                f[IDX(i,j)] = 0.0f;
            }
        }
    }
}

__global__ void update_f_kernel(float* f, float* f_old, float* error_sum, int N) {
    float local_error = 0.0f;

    int interior_size = (N-2) * (N-2);
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx < interior_size) {
        int i = 1 + idx % (N-2);
        int j = 1 + idx / (N-2);

        float t = 0.25f * (f_old[IDX(i-1,j)] +
                          f_old[IDX(i+1,j)] +
                          f_old[IDX(i,j-1)] +
                          f_old[IDX(i,j+1)]);
        float df = t - f_old[IDX(i, j)];
        f[IDX(i,j)] = t;
        local_error += df * df;
    }

    atomicAdd(error_sum, local_error);
}

__global__ void copy_f_to_old_kernel(float* f, float* f_old, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * N;

    if (idx < total) {
        int i = idx % N;
        int j = idx / N;
        if (j >= 1 && j <= N-2 && i >= 1 && i <= N-2)
            f_old[IDX(i,j)] = f[IDX(i,j)];
    }
}

int main() {
    auto start_time = std::chrono::steady_clock::now();

    float* f_host = (float*) aligned_alloc(64, N * N * sizeof(float));
    float* f_old_host = (float*) aligned_alloc(64, N * N * sizeof(float));

    float* f_device;
    float* f_old_device;
    float* error_device;

    cudaMalloc(&f_device, N * N * sizeof(float));
    cudaMalloc(&f_old_device, N * N * sizeof(float));
    cudaMalloc(&error_device, sizeof(float));

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    initialize_data(f_host);
    initialize_data(f_old_host);

    cudaMemcpy(f_device, f_host, N * N * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(f_old_device, f_old_host, N * N * sizeof(float), cudaMemcpyHostToDevice);

    const int max_iters = 10000;
    int num_iters = 0;

    cudaEvent_t start, end;
    cudaEventCreate(&start);
    cudaEventCreate(&end);

    cudaEventRecord(start);

    dim3 block(256);
    dim3 grid((N-2)*(N-2)/256 + 1);

    while (error > tolerance && num_iters < max_iters) {
        error = 0.f;
        cudaMemcpy(error_device, &error, sizeof(float), cudaMemcpyHostToDevice);

        // Launch update kernel
        update_f_kernel<<<grid, block>>>(f_device, f_old_device, error_device, N);

        // Launch copy kernel
        copy_f_to_old_kernel<<<grid, block>>>(f_device, f_old_device, N);

        cudaMemcpy(&error, error_device, sizeof(float), cudaMemcpyDeviceToHost);
        error = sqrtf(error / (N * N));

        if (num_iters % 1000 == 0) {
            std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
        }

        ++num_iters;
    }

    cudaEventRecord(end);
    cudaEventSynchronize(end);
    float time_ms;
    cudaEventElapsedTime(&time_ms, start, end);
    std::cout << "Average execution time per iteration: " << (time_ms * 1e-3f) / num_iters << " (s)\n";

    if (error <= tolerance && num_iters < max_iters) {
        std::cout << "PASS" << std::endl;
    }
    else {
        std::cout << "FAIL" << std::endl;
        cudaFree(f_device);
        cudaFree(f_old_device);
        cudaFree(error_device);
        free(f_host);
        free(f_old_host);
        return -1;
    }

    cudaFree(f_device);
    cudaFree(f_old_device);
    cudaFree(error_device);
    free(f_host);
    free(f_old_host);

    auto end_time = std::chrono::steady_clock::now();
    auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
    double duration = total_time * 1e-9;
    std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

    return 0;
}
